class ParkingSystem:
    def __init__(self, big, medium, small):
        self.big_slots = big
        self.medium_slots = medium
        self.small_slots = small

    def addCar(self, carType: int) -> bool:
        if carType == 1:
            if self.big_slots > 0:
                self.big_slots -= 1
                return True
            elif self.medium_slots > 0:
                self.medium_slots -= 1
                return True
            else:
                return False
        elif carType == 2:
            if self.medium_slots > 0:
                self.medium_slots -= 1
                return True
            elif self.small_slots > 0:
                self.small_slots -= 1
                return True
            else:
                return False
        else:
            return False

